import{_ as t,o as l,c as e,a2 as o}from"./chunks/framework.Pywvta2k.js";const c=JSON.parse('{"title":"针灸甲乙经","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/02-魏晋隋唐/02-针灸甲乙经（皇甫谧）.md","filePath":"tcm-data/02-魏晋隋唐/02-针灸甲乙经（皇甫谧）.md","lastUpdated":1781084559000}'),r={name:"tcm-data/02-魏晋隋唐/02-针灸甲乙经（皇甫谧）.md"};function i(n,a,s,h,_,d){return l(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="针灸甲乙经" tabindex="-1">针灸甲乙经 <a class="header-anchor" href="#针灸甲乙经" aria-label="Permalink to &quot;针灸甲乙经&quot;">​</a></h1><blockquote><p>皇甫谧（215-282年），甘肃灵台人 中国第一部针灸学专著</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>成书</strong>：西晋，公元259年（与《脉经》几乎同时）</li><li><strong>卷数</strong>：12卷，128篇</li><li><strong>内容</strong>：以《素问》《灵枢》《明堂孔穴》三部为基础，删繁举要</li><li><strong>学术地位</strong>：针灸学之宗，&quot;皇甫谧之功，不在仲景下&quot;</li></ul><hr><h2 id="二、核心内容" tabindex="-1">二、核心内容 <a class="header-anchor" href="#二、核心内容" aria-label="Permalink to &quot;二、核心内容&quot;">​</a></h2><h3 id="_1-经络腧穴" tabindex="-1">1. 经络腧穴 <a class="header-anchor" href="#_1-经络腧穴" aria-label="Permalink to &quot;1. 经络腧穴&quot;">​</a></h3><ul><li>确定<strong>349个穴位</strong>（单穴49，双穴300）</li><li>按头面、躯干、四肢分部定位</li><li>详论各穴主治</li></ul><h3 id="_2-针刺手法" tabindex="-1">2. 针刺手法 <a class="header-anchor" href="#_2-针刺手法" aria-label="Permalink to &quot;2. 针刺手法&quot;">​</a></h3><ul><li>针刺深浅（&quot;病有浮沉，刺有浅深&quot;）</li><li>留针时间</li><li>补泻手法（迎随、呼吸、徐疾等）</li></ul><h3 id="_3-灸法" tabindex="-1">3. 灸法 <a class="header-anchor" href="#_3-灸法" aria-label="Permalink to &quot;3. 灸法&quot;">​</a></h3><ul><li>艾灸的壮数</li><li>灸法治疗禁忌</li></ul><hr><h2 id="三、对后世的影响" tabindex="-1">三、对后世的影响 <a class="header-anchor" href="#三、对后世的影响" aria-label="Permalink to &quot;三、对后世的影响&quot;">​</a></h2><ul><li>**孙思邈《千金方》**大量引用</li><li>宋代王惟一铸造针灸铜人，腧穴定位以《甲乙经》为据</li><li>日本、韩国传统针灸均以本书为基础</li></ul><blockquote><p><strong>「针灸之经，肇自黄帝，而备于皇甫。」</strong></p></blockquote><hr><p><em>本条目为精简框架版。可在后续扩展到常用腧穴速查、十四经循行、针灸治疗常见病等内容。</em></p>',19)])])}const q=t(r,[["render",i]]);export{c as __pageData,q as default};
